import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Booking() {
  const [bookings, setBookings] = useState([]);
  const [userName, setUserName] = useState("");
  const [selectedService, setSelectedService] = useState("");

  const navigate = useNavigate();

  const services = [
    { name: "Web Development", desc: "Modern websites & dashboards" },
    { name: "App Development", desc: "Mobile apps (Android / iOS)" },
    { name: "UI/UX Design", desc: "Clean modern interface design" },
    { name: "SEO Optimization", desc: "Rank higher on Google" },
    { name: "Bug Fixing", desc: "Fix issues in your existing app" }
  ];

  const fetchBookings = () => {
    const token = localStorage.getItem("token");

    axios
      .get("http://localhost:5000/api/bookings", {
        headers: {
          Authorization: `Bearer ${token}`
        }
      })
      .then(res => setBookings(res.data));
  };

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) return navigate("/login");
    fetchBookings();
  }, []);

  const bookService = () => {
    const token = localStorage.getItem("token");

    if (!userName || !selectedService) {
      alert("Fill all fields");
      return;
    }

    axios.post(
      "http://localhost:5000/api/bookings",
      {
        userName,
        serviceName: selectedService
      },
      {
        headers: {
          Authorization: `Bearer ${token}`
        }
      }
    ).then(() => {
      fetchBookings();
      setUserName("");
      setSelectedService("");
    });
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
    <div style={styles.page}>
      
      {/* HEADER */}
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>Booking Dashboard</h1>
          <p style={styles.subtitle}>Manage your services easily</p>
        </div>

        <button style={styles.logout} onClick={logout}>
          Logout
        </button>
      </div>

      {/* CONTENT */}
      <div style={styles.layout}>
        
        {/* LEFT - FORM */}
        <div style={styles.card}>
          <h2 style={styles.cardTitle}>Create Booking</h2>

          <input
            style={styles.input}
            placeholder="Your Name"
            value={userName}
            onChange={(e) => setUserName(e.target.value)}
          />

          <p style={styles.label}>Select a service</p>

          <div style={styles.services}>
            {services.map((s, i) => (
              <div
                key={i}
                onClick={() => setSelectedService(s.name)}
                style={{
                  ...styles.serviceCard,
                  border:
                    selectedService === s.name
                      ? "1px solid #3b82f6"
                      : "1px solid rgba(255,255,255,0.08)"
                }}
              >
                <h4>{s.name}</h4>
                <p>{s.desc}</p>
              </div>
            ))}
          </div>

          <button style={styles.button} onClick={bookService}>
            Confirm Booking
          </button>
        </div>

        {/* RIGHT - BOOKINGS */}
        <div style={styles.card}>
          <h2 style={styles.cardTitle}>Your Bookings</h2>

          {bookings.length === 0 ? (
            <p style={{ opacity: 0.6 }}>No bookings yet</p>
          ) : (
            bookings.map((b, i) => (
              <div key={i} style={styles.bookingItem}>
                <div>
                  <p style={{ margin: 0, fontWeight: 500 }}>{b.userName}</p>
                  <span style={{ opacity: 0.6, fontSize: 13 }}>
                    {b.serviceName}
                  </span>
                </div>
              </div>
            ))
          )}
        </div>

      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    padding: "40px",
    background: "#0b1220",
    color: "white",
    fontFamily: "Inter, sans-serif"
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "30px"
  },

  title: {
    margin: 0,
    fontSize: "28px"
  },

  subtitle: {
    margin: 0,
    opacity: 0.6
  },

  logout: {
    padding: "10px 14px",
    borderRadius: "10px",
    border: "none",
    background: "#ef4444",
    color: "white",
    cursor: "pointer"
  },

  layout: {
    display: "grid",
    gridTemplateColumns: "1.2fr 1fr",
    gap: "20px"
  },

  card: {
    background: "rgba(255,255,255,0.04)",
    border: "1px solid rgba(255,255,255,0.08)",
    borderRadius: "16px",
    padding: "20px",
    backdropFilter: "blur(10px)"
  },

  cardTitle: {
    marginBottom: "15px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid rgba(255,255,255,0.1)",
    background: "transparent",
    color: "white",
    marginBottom: "15px",
    outline: "none"
  },

  label: {
    fontSize: "14px",
    opacity: 0.7
  },

  services: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
    marginBottom: "15px"
  },

  serviceCard: {
    padding: "12px",
    borderRadius: "12px",
    cursor: "pointer",
    background: "rgba(255,255,255,0.03)"
  },

  button: {
    width: "100%",
    padding: "12px",
    borderRadius: "12px",
    border: "none",
    background: "#3b82f6",
    color: "white",
    cursor: "pointer",
    fontWeight: "bold"
  },

  bookingItem: {
    padding: "12px",
    borderRadius: "10px",
    background: "rgba(255,255,255,0.03)",
    marginBottom: "10px"
  }
};

export default Booking;
